class Solution:
    def minSpeedOnTime(self, dist: List[int], hour: float) -> int:
    if len(dist) >= hour + 1  : return -1
    left,right = 1, ceil(max(max(dist),dist[-1]/(1 if hour.is_integer() else hour-int(hour))))
    while left<right:
        mid=(left+right)//2
        if sum([ceil(i/mid) for i in dist[:-1]])+(dist[-1]/mid) <= hour :
            right=mid
        else:
            left=mid+1
    return left

class BIT():
    def __init__(self, n):
        self.n = n
    self.tree = [0] * (n + 1)

    def sum(self, i):
        ans = 0
        i += 1
        while i > 0:
            ans += self.tree[i]
            i -= (i & (-i))
        return ans

    def update(self, i, value):
        i += 1
        while i <= self.n:
            self.tree[i] += value
            i += (i & (-i))


